{
  "domain_analysis": {
    "business_context": "A logistics platform introducing automated route optimization for drivers at shift start, with dynamic recalculation triggers, customer notification windows, vehicle-class enforcement, and configurable stop duration. This spans multiple bounded contexts: route planning, fleet/driver management, delivery lifecycle, and customer notifications.",
    "bounded_context": "Primary: Route Planning. Adjacent: Fleet Management, Delivery Management, Customer Notification",
    "ubiquitous_language": [
      { "term": "Zone", "definition": "A geographic region used to partition deliveries and assign them to drivers. A zone is the fundamental unit of route scoping — deliveries belong to a zone, and drivers operate within a zone during a shift." },
      { "term": "Optimized Route", "definition": "An ordered sequence of delivery stops calculated by the system to minimize travel time/distance for a driver within their assigned zone. Not a suggestion — it is the system's authoritative plan for the driver's shift." },
      { "term": "Pending Delivery", "definition": "A delivery that has been accepted into the system, assigned to a zone, but not yet completed, failed, or cancelled. Only pending deliveries are eligible for route inclusion." },
      { "term": "Route Recalculation", "definition": "The act of recomputing the optimized route in response to a defined trigger event (new delivery, failed delivery, or driver deviation). Replaces the current route entirely — it is not a patch." },
      { "term": "Driver Deviation", "definition": "When a driver's actual geographic position or stop sequence diverges from the optimized route beyond an acceptable threshold. The spec says 'manually deviates from the suggested route' — this implies the system must detect deviation, not rely on the driver to report it." },
      { "term": "Next 3 Stops Window", "definition": "A sliding notification window: the set of three delivery stops immediately ahead of the driver's current position in the route. Entering this window triggers customer notification. This is a customer-facing promise." },
      { "term": "Licensed Vehicle Class", "definition": "A classification of the vehicle a driver is licensed/authorized to operate (e.g., motorcycle, van, truck, freight). Each delivery has a required vehicle class. This is a hard constraint from Fleet Management, not a route planning preference." },
      { "term": "Shift", "definition": "A bounded work period for a driver. Route assignment is triggered by shift start. A shift scopes the driver to a zone and a time window." },
      { "term": "Stop Duration", "definition": "The estimated time a driver spends at each delivery stop. Defaults to 4 minutes globally but is overridable per zone by the operations team. Used for ETA calculations and route optimization." },
      { "term": "Failed Delivery", "definition": "A delivery attempt that did not result in successful handoff to the recipient. Triggers route recalculation because the stop is removed (or deprioritized) from the active route." }
    ]
  },

  "business_rules": [
    {
      "id": "BR-1",
      "rule": "A driver MUST NOT be assigned a delivery whose required vehicle class exceeds or is incompatible with the driver's licensed vehicle class.",
      "invariant": true,
      "invariant_justification": "This is a safety and legal constraint. A motorcycle courier physically cannot carry a freight pallet. Violating this creates liability, regulatory violations, and guaranteed delivery failure. No business policy can override physics or law.",
      "testable_assertion": "For every delivery in a driver's assigned route, delivery.requiredVehicleClass must be compatible with driver.licensedVehicleClass. If any assignment violates this, the system is in a corrupt state."
    },
    {
      "id": "BR-2",
      "rule": "When a driver starts their shift, the system MUST automatically generate an optimized route from all pending deliveries in the driver's assigned zone.",
      "invariant": false,
      "invariant_justification": "This is a workflow policy. The business could decide to allow manual route creation or pre-shift route building. The trigger (shift start) is a business decision, not a physical constraint.",
      "testable_assertion": "Within T seconds of a driver's shift starting, a route must exist for that driver containing only pending deliveries from their assigned zone."
    },
    {
      "id": "BR-3",
      "rule": "The route MUST be recalculated when a new pending delivery is added to the driver's active zone.",
      "invariant": false,
      "invariant_justification": "This is an optimization policy. The business could choose to batch new deliveries or defer recalculation. The system would not be corrupt without it — just suboptimal.",
      "testable_assertion": "When a delivery transitions to 'pending' in a zone with an active driver route, a route recalculation event is emitted and a new route is generated that includes the new delivery."
    },
    {
      "id": "BR-4",
      "rule": "The route MUST be recalculated when a delivery on the active route is marked as failed.",
      "invariant": false,
      "invariant_justification": "Optimization policy. Failed delivery removal is important for efficiency but not a safety or data-integrity constraint.",
      "testable_assertion": "When a delivery on an active route transitions to 'failed', a route recalculation is triggered and the resulting route excludes the failed delivery (unless business rules dictate a retry)."
    },
    {
      "id": "BR-5",
      "rule": "The route MUST be recalculated when the driver manually deviates from the suggested route.",
      "invariant": false,
      "invariant_justification": "Optimization policy. The driver's real-world position has diverged from the plan, so the plan must adapt. But the system is not corrupt without it — just stale.",
      "testable_assertion": "When the system detects that the driver's actual position or stop sequence has diverged from the planned route beyond a configured threshold, a recalculation is triggered using the driver's current position as the new origin."
    },
    {
      "id": "BR-6",
      "rule": "Customers MUST be notified when their delivery enters the 'next 3 stops' window of the driver's active route.",
      "invariant": false,
      "invariant_justification": "Customer experience policy. The notification threshold (3 stops) is a business decision that could change. The number 3 is arbitrary — could be 2 or 5.",
      "testable_assertion": "When a route is calculated or recalculated, for each delivery now in positions 1-3 of the route whose customer has NOT already been notified for this delivery attempt, a customer notification is sent."
    },
    {
      "id": "BR-7",
      "rule": "The default estimated stop duration is 4 minutes per delivery stop, overridable per zone by the operations team.",
      "invariant": false,
      "invariant_justification": "Configurable operational parameter. The 4-minute default and the override mechanism are both policy decisions.",
      "testable_assertion": "Route ETA calculations use the zone-specific stop duration if configured, otherwise the 4-minute default. The operations team can set and update the per-zone override without a code deployment."
    },
    {
      "id": "BR-8",
      "rule": "A driver's route MUST only contain deliveries within their assigned zone.",
      "invariant": true,
      "invariant_justification": "Zone boundaries define operational jurisdiction, insurance coverage areas, and regulatory compliance. Cross-zone assignment breaks the fundamental partitioning model and could result in drivers operating outside their authorized area.",
      "testable_assertion": "Every delivery on a driver's route must have a zone that matches the driver's active shift zone. No cross-zone deliveries may appear on a route."
    },
    {
      "id": "BR-9",
      "rule": "A route recalculation MUST preserve already-completed stops — it recalculates the remaining sequence only.",
      "invariant": true,
      "invariant_justification": "Completed deliveries are historical facts. A recalculation that removes or reorders completed stops would corrupt delivery records and break audit trails. You cannot un-deliver a package.",
      "testable_assertion": "After recalculation, all previously completed delivery stops retain their completed status and are not reinserted into the active route sequence."
    }
  ],

  "acceptance_criteria": [
    {
      "id": "AC-1",
      "given": "A driver starts their shift and there are 5 pending deliveries in their zone, all compatible with their vehicle class",
      "when": "The shift start event is processed",
      "then": "An optimized route is generated containing exactly those 5 deliveries, ordered to minimize travel time/distance"
    },
    {
      "id": "AC-2",
      "given": "A driver has an active route with 8 remaining stops",
      "when": "A new pending delivery is added to their zone that is compatible with their vehicle class",
      "then": "The route is recalculated to include the new delivery (9 stops), preserving any already-completed stops"
    },
    {
      "id": "AC-3",
      "given": "A driver has an active route and delivery #4 is marked as failed",
      "when": "The failed delivery event is processed",
      "then": "The route is recalculated excluding the failed delivery from remaining stops"
    },
    {
      "id": "AC-4",
      "given": "A driver deviates from their route (e.g., skips stop #2 and drives toward stop #5)",
      "when": "The deviation is detected by the system",
      "then": "The route is recalculated using the driver's current position as the new starting point"
    },
    {
      "id": "AC-5",
      "given": "A driver completes a stop and the next delivery in the recalculated route was previously at position #4 but is now at position #3",
      "when": "That delivery enters the 'next 3 stops' window for the first time",
      "then": "The customer for that delivery receives exactly one notification"
    },
    {
      "id": "AC-6",
      "given": "A pending delivery requires a freight vehicle and the only active driver in the zone has a motorcycle license",
      "when": "Route generation runs for that driver",
      "then": "The freight delivery is excluded from the route; it remains unassigned and pending"
    },
    {
      "id": "AC-7",
      "given": "The operations team has set the stop duration for Zone A to 6 minutes",
      "when": "A route is calculated for a driver in Zone A with 10 stops",
      "then": "The ETA calculations use 6 minutes per stop (not the 4-minute default)"
    },
    {
      "id": "AC-8",
      "given": "A driver's route is recalculated due to a new delivery being added",
      "when": "The customer for delivery at position #2 was already notified in the previous route calculation",
      "then": "The customer is NOT notified again (idempotent notification)"
    },
    {
      "id": "AC-9",
      "given": "A new delivery is added to a zone but it requires a vehicle class incompatible with the active driver",
      "when": "Route recalculation is triggered",
      "then": "The incompatible delivery is NOT added to the route, and the recalculation proceeds with only compatible deliveries"
    }
  ],

  "edge_cases": [
    {
      "scenario": "Multiple recalculation triggers fire simultaneously (new delivery added AND driver deviates at the same moment)",
      "expected_behavior": "The system must serialize or debounce recalculations. Only one recalculation should execute, incorporating all pending state changes. Concurrent recalculations could produce conflicting routes."
    },
    {
      "scenario": "A driver starts a shift in a zone with zero pending deliveries",
      "expected_behavior": "The system creates an empty route (or a 'waiting' state). When the first delivery arrives, BR-3 triggers recalculation and the driver gets their first stop. The system must not error on an empty route."
    },
    {
      "scenario": "All remaining deliveries on a route are marked as failed",
      "expected_behavior": "The route becomes empty. The driver should be placed in an idle/waiting state, not stuck on a stale route. The system should surface this to dispatch."
    },
    {
      "scenario": "A delivery is added to a zone where no active driver has a compatible vehicle class",
      "expected_behavior": "The delivery remains pending and unassigned. The system should flag this to dispatch/operations as an unserviceable delivery — it must NOT silently drop it or force-assign it to an incompatible driver."
    },
    {
      "scenario": "Driver is on stop #1 of 3 remaining stops — all 3 customers are already in the notification window. A recalculation reorders stops #2 and #3.",
      "expected_behavior": "No duplicate notifications are sent. The customers were already notified. However, ETA updates may need to be sent if the order changed significantly — spec is silent on ETA update notifications."
    },
    {
      "scenario": "A driver's shift ends while deliveries remain on their route",
      "expected_behavior": "Spec is silent on this. The remaining deliveries must return to 'pending' and be eligible for reassignment to another driver. They must not be orphaned."
    },
    {
      "scenario": "Operations team sets stop duration to 0 minutes or a negative value",
      "expected_behavior": "The system must validate the override. Stop duration must be a positive value. Zero or negative values would produce nonsensical ETAs and break customer expectations."
    },
    {
      "scenario": "A delivery is added to a zone while a route recalculation for that zone is already in progress",
      "expected_behavior": "The system must either queue another recalculation after the current one completes (ensuring the new delivery is picked up) or restart the current recalculation with the updated delivery set. The new delivery must not be silently missed."
    },
    {
      "scenario": "Driver deviation detection: the driver takes a different road to the SAME next stop (not actually deviating from sequence, just using alternate directions)",
      "expected_behavior": "This should NOT trigger a recalculation. Deviation means sequence deviation (going to a different stop than planned), not geographic path deviation. The spec says 'deviates from the suggested route' which is ambiguous — this needs clarification."
    }
  ],

  "business_impact": {
    "financial": "Route optimization directly reduces fuel costs, increases deliveries-per-shift, and improves driver utilization. Dynamic recalculation captures revenue from mid-shift deliveries that would otherwise wait for next shift. Vehicle class enforcement prevents costly failed delivery attempts (driver arrives but physically cannot carry the package).",
    "operational": "Automated route assignment eliminates manual dispatch overhead. Recalculation triggers add system load — each trigger potentially recomputes an entire route, so debouncing and performance are critical at scale. Per-zone stop duration override gives operations teams local tuning capability without engineering involvement.",
    "user": "Customers get proactive notification when their delivery is imminent (next 3 stops ≈ 12-18 minutes out with default timing), reducing missed deliveries and improving satisfaction. Drivers get clear, optimized instructions instead of self-routing, reducing cognitive load and decision fatigue.",
    "risk": "Frequent recalculations could create route 'thrash' — drivers constantly receiving new instructions, leading to confusion and frustration. Vehicle class enforcement is a safety-critical path; any bypass creates legal liability. Customer notification timing is a brand promise — if ETAs are wrong due to bad stop duration config, trust erodes.",
    "stakeholders_affected": [
      { "group": "Drivers", "impact": "Primary users. Gain optimized routes but lose autonomy. Frequent recalculations may be disruptive. Must trust the system's decisions to adopt it." },
      { "group": "Customers (recipients)", "impact": "Receive delivery proximity notifications. Improved experience if ETAs are accurate; frustration if notifications are premature or duplicated." },
      { "group": "Operations Team", "impact": "Gain zone-level configuration control (stop duration). Responsible for monitoring unserviceable deliveries and handling vehicle class mismatches. Reduced manual dispatch burden." },
      { "group": "Dispatch/Fleet Management", "impact": "Must handle edge cases: unassignable deliveries, shift-end orphaned deliveries, driver deviations. Need visibility into why certain deliveries are excluded from routes." },
      { "group": "Finance/Business", "impact": "Expects measurable improvement in deliveries-per-shift and fuel costs. Route optimization ROI depends on algorithm quality." }
    ]
  },

  "confidence": {
    "level": 62,
    "reasoning": "The spec covers the happy path well and identifies clear triggers and constraints. However, several operationally critical details are missing: deviation detection definition (geographic vs. sequence), shift-end behavior, recalculation concurrency strategy, and what happens to incompatible/unassignable deliveries. The notification window is clear but ETA update behavior on reorder is unspecified. Vehicle class enforcement is well-stated but the compatibility model (is it hierarchical or categorical?) is undefined.",
    "high_confidence_areas": [
      "Vehicle class constraint is a hard invariant — clearly a safety/legal requirement",
      "Route generation at shift start is well-defined",
      "Three recalculation triggers are explicitly enumerated",
      "Customer notification window of 'next 3 stops' is clear",
      "Stop duration default and override mechanism is straightforward"
    ],
    "low_confidence_areas": [
      "What constitutes 'driver deviation' — geographic path divergence vs. stop sequence divergence",
      "Shift-end behavior for incomplete routes — not specified at all",
      "Recalculation concurrency and debouncing strategy",
      "Vehicle class compatibility model — hierarchical (truck driver can do van deliveries?) or strict categorical matching",
      "Whether failed deliveries are permanently removed or eligible for retry on the same route",
      "ETA update notifications when route reorders but customer was already notified"
    ],
    "assumptions": [
      "A driver is assigned to exactly one zone per shift",
      "Zone assignment is determined before/at shift start and does not change mid-shift",
      "Route optimization means minimizing travel time or distance — the optimization objective is not specified",
      "The 'next 3 stops' notification is sent once per delivery attempt, not on every recalculation",
      "Vehicle class compatibility is checked at route assignment time, not just at shift start",
      "Failed deliveries are excluded from the current route and not automatically retried"
    ]
  },

  "escalations": [
    {
      "type": "ambiguity",
      "description": "The spec says 'driver manually deviates from the suggested route' but does not define what constitutes deviation. Is it (A) the driver going to a different stop than the next planned one (sequence deviation), or (B) the driver taking a different road to the same stop (geographic deviation)? These require fundamentally different detection mechanisms and have very different recalculation implications.",
      "affected_stakeholders": ["Drivers", "Operations Team", "Engineering"],
      "options": [
        "A: Sequence deviation only — recalculate when driver completes a stop that was not next in sequence",
        "B: Geographic deviation — recalculate when driver's GPS position diverges from planned path beyond a threshold",
        "C: Both — sequence deviation triggers immediate recalculation, geographic deviation triggers after a distance/time threshold"
      ],
      "recommendation": "Option A (sequence deviation). Geographic deviation is noisy (GPS drift, road closures, local knowledge) and would cause excessive recalculations. Sequence deviation is a clear, discrete event that genuinely invalidates the optimized order."
    },
    {
      "type": "ambiguity",
      "description": "Vehicle class compatibility model is undefined. Is it hierarchical (a truck-licensed driver can handle van-class deliveries) or strictly categorical (a truck driver can ONLY handle truck-class deliveries)? This fundamentally changes route composition.",
      "affected_stakeholders": ["Drivers", "Dispatch/Fleet Management", "Operations Team"],
      "options": [
        "A: Hierarchical — higher class includes lower (truck >= van >= motorcycle)",
        "B: Strict categorical — each class is independent, driver must exactly match",
        "C: Matrix-based — explicit compatibility mapping configured by operations"
      ],
      "recommendation": "Option C (matrix-based) for flexibility, but Option A is the most common model in real-world logistics. Need product team clarification."
    },
    {
      "type": "missing_context",
      "description": "No specification for what happens when a driver's shift ends with remaining deliveries on their route. Are they returned to 'pending'? Assigned to the next shift? Flagged for operations? This is a critical operational scenario that happens daily.",
      "affected_stakeholders": ["Drivers", "Customers", "Operations Team", "Dispatch/Fleet Management"],
      "options": [
        "A: Remaining deliveries return to 'pending' and are auto-assigned to next available driver in the zone",
        "B: Remaining deliveries are flagged for manual dispatch review",
        "C: Driver's shift is extended until route is complete (with overtime implications)"
      ],
      "recommendation": "Option A with B as fallback — remaining deliveries return to pending and trigger route recalculation for other active drivers in the zone, with operations notification if no active drivers remain."
    },
    {
      "type": "ambiguity",
      "description": "Recalculation frequency is unbounded. If deliveries are being added frequently (e.g., 10 new deliveries in 5 minutes), the system could recalculate 10 times. No debounce, batching, or rate-limiting strategy is specified. This is both a performance and driver-experience concern.",
      "affected_stakeholders": ["Drivers", "Engineering", "Operations Team"],
      "options": [
        "A: Recalculate immediately on every trigger (simplest, most aggressive)",
        "B: Debounce — batch triggers within a time window (e.g., 30 seconds) and recalculate once",
        "C: Rate-limit — no more than one recalculation per N minutes, queue triggers"
      ],
      "recommendation": "Option B with a configurable debounce window per zone. Immediate recalculation on failed-delivery and deviation triggers, but debounced for new-delivery triggers."
    }
  ],

  "rejection_reasons": []
}

